 20→    wJogWord := wJogWord AND 16#FFFC;
 21→    %UW0.9.1 := wJogWord;
 22→
 23→    %MW400 := 16#0002;
 24→    %MW401 := 0;
 25→    g_bStopExec := TRUE;
 26→
 27→ELSE
 28→
 29→    (* 1. PC 명령 비트 읽기 (MW300) *)
 30→    bCmdHome    := %MW300.0;
 31→    bCmdMove    := %MW300.1;
 32→    bCmdStop    := %MW300.4;
 33→    bCmdReset   := %MW300.5;
 34→
 35→    (* 제어 부가 비트 (MW301) *)
 36→    bMoveRel    := %MW301.1;
 37→
 38→    (* 2. 파라미터 읽기 (MW310~313, DINT = 2 WORD) *)
 39→    dinTargetPos := WORD_TO_DINT(%MW310) + WORD_TO_DINT(%MW311) * 65536;
 40→    dinTargetVel := WORD_TO_DINT(%MW312) + WORD_TO_DINT(%MW313) * 65536;
 41→
 42→    (* 3. 수동 엣지 검출 *)
 43→    bEdgeHome   := bCmdHome   AND NOT bPrevHome;
 44→    bEdgeMove   := bCmdMove   AND NOT bPrevMove;
 45→    bEdgeStop   := bCmdStop   AND NOT bPrevStop;
 46→    bEdgeReset  := bCmdReset  AND NOT bPrevReset;
 47→
 48→    bPrevHome   := bCmdHome;
 49→    bPrevMove   := bCmdMove;
 50→    bPrevStop   := bCmdStop;
 51→    bPrevReset  := bCmdReset;
 52→
 53→    (* 4. 원점복귀 — APM_ORG *)
 54→    IF bEdgeHome THEN
 55→        bOrgReq := TRUE;
 56→    END_IF;
 57→
 58→    g_FB_Org(REQ := bOrgReq, BASE := 0, SLOT := 9, AXIS := 0,
 59→             DONE => bOrgDone, STAT => wOrgStat);
 60→
 61→    IF bOrgDone OR (wOrgStat <> 0) THEN
 62→        bOrgReq := FALSE;
 63→    END_IF;
 64→
 65→    (* 5. 위치 이동 — APM_DST *)
 66→    IF bEdgeMove THEN
 67→        bDstReq := TRUE;
 68→    END_IF;
 69→
 70→    g_FB_Dst(REQ := bDstReq, BASE := 0, SLOT := 9, AXIS := 0,
 71→             ADDR := dinTargetPos, SPEED := DINT_TO_UDINT(dinTargetVel),
 72→             DWELL := 0, MCODE := 0,
 73→             POS_SPD := FALSE, ABS_INC := bMoveRel,
 74→             TIME_SEL := 0,
 75→             DONE => bDstDone, STAT => wDstStat);
 76→
 77→    IF bDstDone OR (wDstStat <> 0) THEN
 78→        bDstReq := FALSE;
 79→    END_IF;
 80→
 81→    (* 6. 정지 — APM_STP *)
 82→    IF bEdgeStop THEN
 83→        bStpReq := TRUE;
 84→    END_IF;
 85→
 86→    g_FB_Stp(REQ := bStpReq, BASE := 0, SLOT := 9, AXIS := 0,
 87→             DEC_TIME := 0, DONE => bStpDone, STAT => wStpStat);
 88→
 89→    IF bStpDone OR (wStpStat <> 0) THEN
 90→        bStpReq := FALSE;
 91→    END_IF;
 92→
 93→    (* 7. 폴트 리셋 — APM_RST *)
 94→    IF bEdgeReset THEN
 95→        bRstReq := TRUE;
 96→    END_IF;
 97→
 98→    g_FB_Rst(REQ := bRstReq, BASE := 0, SLOT := 9, AXIS := 0,
 99→             INH_OFF := FALSE, DONE => bRstDone, STAT => wRstStat);
100→
101→    IF bRstDone OR (wRstStat <> 0) THEN
102→        bRstReq := FALSE;
103→    END_IF;
104→
105→    (* 8. 서보 상태 비트 → MW400 *)
106→    wStatus := 0;
107→    wRdyStat := %UW0.9.0;
108→
109→    (* bit0: 동작 중 *)
110→    IF bOrgReq OR bDstReq THEN
111→        wStatus := wStatus OR 16#0001;
112→    END_IF;
113→    (* bit1: 에러 발생 *)
114→    IF (wOrgStat <> 0) OR (wDstStat <> 0) OR (wStpStat <> 0) THEN
115→        wStatus := wStatus OR 16#0002;
116→    END_IF;
117→    (* bit4: 위치결정모듈 RDY (비트15) *)
118→    IF (wRdyStat AND 16#8000) <> 16#0000 THEN
119→        wStatus := wStatus OR 16#0010;
120→    END_IF;
121→    (* bit6: 서보MC 출력 상태 *)
122→    IF %QX0.0.5 THEN
123→        wStatus := wStatus OR 16#0040;
124→    END_IF;
125→
126→    %MW400 := wStatus;
127→
128→    (* 9. 명령 응답 비트 → MW401 *)
129→    wResponse := 0;
130→
131→    IF bOrgDone THEN
132→        wResponse := wResponse OR 16#0001;
133→    END_IF;
134→    IF bDstDone THEN
135→        wResponse := wResponse OR 16#0002;
136→    END_IF;
137→    IF wOrgStat <> 0 THEN
138→        wResponse := wResponse OR 16#0004;
139→    END_IF;
140→    IF wDstStat <> 0 THEN
141→        wResponse := wResponse OR 16#0008;
142→    END_IF;
143→    IF bRstDone THEN
144→        wResponse := wResponse OR 16#0010;
145→    END_IF;
146→
147→    %MW401 := wResponse;
148→
149→    (* 10. 위치/속도 → MW410~415 (U영역 직접 복사) *)
150→    %MW410 := %UW0.9.2;   (* 현재 위치 하위 *)
151→    %MW411 := %UW0.9.3;   (* 현재 위치 상위 *)
152→    %MW412 := %UW0.9.4;   (* 현재 속도 하위 *)
153→    %MW413 := %UW0.9.5;   (* 현재 속도 상위 *)
154→    %MW414 := UINT_TO_WORD(wOrgStat) OR UINT_TO_WORD(wDstStat) OR UINT_TO_WORD(wStpStat) OR UINT_TO_WORD(wRstStat);
155→    %MW415 := 0;
156→
157→END_IF;
