 27→    // 출력 캐시 — 토글 시 현재 값 기반으로 비트 변경 후 쓰기
 28→    private readonly ushort[] _outputCache = new ushort[10];
 29→
 30→    // 서보/시스템 WRITE 캐시 — MW300,301,500 (ServoSystemWords index 0,1,4)
 31→    private readonly ushort[] _servoSysCache = new ushort[6];
 32→    // ServoSystemWords 인덱스 → MW 주소 매핑
 33→    private static readonly int[] ServoSysMwAddresses = [300, 301, 400, 401, 500, 501];
 34→
 35→    // 서보 파라미터 (DINT 값)
 36→    private int _targetPos, _targetVel, _jogVel, _actPos, _actVel;
 37→    private ushort _errCode, _actPosDeg;
 38→
 39→    public int TargetPos { get => _targetPos; set { _targetPos = value; OnPropertyChanged(); } }
 40→    public int TargetVel { get => _targetVel; set { _targetVel = value; OnPropertyChanged(); } }
 41→    public int JogVel { get => _jogVel; set { _jogVel = value; OnPropertyChanged(); } }
 42→    public int ActPos { get => _actPos; set { _actPos = value; OnPropertyChanged(); } }
 43→    public int ActVel { get => _actVel; set { _actVel = value; OnPropertyChanged(); } }
 44→    public ushort ErrCode { get => _errCode; set { _errCode = value; OnPropertyChanged(); } }
 45→    public ushort ActPosDeg { get => _actPosDeg; set { _actPosDeg = value; OnPropertyChanged(); } }
 46→
 47→    // Heartbeat 카운터 (MW500: bit0~7=카운터, bit8=PC_READY)
 48→    private byte _heartbeatCount;
 49→
 50→    // PLC 상태 (MW501 파싱)
 51→    private bool _plcCommOk, _plcEmoActive, _plcServoErr, _plcWdTimeout, _plcRun;
 52→    private byte _plcHeartbeat;
 53→
 54→    public bool PlcCommOk { get => _plcCommOk; set { _plcCommOk = value; OnPropertyChanged(); } }
 55→    public bool PlcEmoActive { get => _plcEmoActive; set { _plcEmoActive = value; OnPropertyChanged(); } }
 56→    public bool PlcServoErr { get => _plcServoErr; set { _plcServoErr = value; OnPropertyChanged(); } }
 57→    public bool PlcWdTimeout { get => _plcWdTimeout; set { _plcWdTimeout = value; OnPropertyChanged(); } }
 58→    public bool PlcRun { get => _plcRun; set { _plcRun = value; OnPropertyChanged(); } }
 59→    public byte PlcHeartbeat { get => _plcHeartbeat; set { _plcHeartbeat = value; OnPropertyChanged(); } }
 60→
 61→    // 연결 상태
 62→    private string _connectionStatus = "미연결";
 63→    private bool _isConnected;
 64→    private int _cycleMs;
 65→
 66→    public string ConnectionStatus { get => _connectionStatus; set { _connectionStatus = value; OnPropertyChanged(); } }
 67→    public bool IsConnected { get => _isConnected; set { _isConnected = value; OnPropertyChanged(); } }
 68→    public int CycleMs { get => _cycleMs; set { _cycleMs = value; OnPropertyChanged(); } }
 69→
 70→
 71→    public IoMonitorViewModel()
 72→    {
 73→        foreach (var w in MemoryMapDefinition.InputMap)
 74→            InputWords.Add(new WordViewModel(w));
 75→
 76→        foreach (var w in MemoryMapDefinition.OutputMap)
 77→            OutputWords.Add(new WordViewModel(w));
 78→
 79→        foreach (var w in MemoryMapDefinition.ServoAndSystemMap)
 80→            ServoSystemWords.Add(new WordViewModel(w));
