 86→        bDstTimeout := FALSE;   (* [Fix3] 타임아웃 플래그 초기화 *)
 87→    END_IF;
 88→
 89→    g_FB_Dst(REQ := bDstReq, BASE := 0, SLOT := 9, AXIS := 0,
 90→             ADDR := dinTargetPos, SPEED := DINT_TO_UDINT(dinTargetVel),
 91→             DWELL := 0, MCODE := 0,
 92→             POS_SPD := FALSE, ABS_INC := bMoveRel,
 93→             TIME_SEL := 0,
