156→        bDstTimeout := FALSE;
157→    END_IF;
158→
159→    (* 8. 서보 상태 비트 → MW400 *)
160→    wStatus := 0;
161→    wRdyStat := %UW0.9.0;
162→
163→    (* bit0: 동작 중 *)
164→    IF bOrgReq OR bDstReq THEN
165→        wStatus := wStatus OR 16#0001;
166→    END_IF;
