176→    IF (wRdyStat AND 16#8000) <> 16#0000 THEN
177→        wStatus := wStatus OR 16#0010;
178→    END_IF;
179→    (* bit6: 서보MC 출력 상태 *)
180→    IF %QX0.0.5 THEN
181→        wStatus := wStatus OR 16#0040;
182→    END_IF;
183→
184→    %MW400 := wStatus;
185→
186→    (* 9. 명령 응답 비트 → MW401 *)
